mapper.select:
SELECT id, biz_type, bill_id, bill_no, config_id, device_sn, content_hash,
       status, resp_code, resp_msg, cost_ms, user_id, user_name, client_ip, create_time
FROM sys_feie_print_log


        AND biz_type = #{bizType}


        AND bill_id = #{billId}


        AND status = #{status}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY id DESC
